# ==================== ВСПОМОГАТЕЛЬНЫЕ ФУНКЦИИ ====================
def get_rule_by_id(rule_id):
    for r in RULES:
        if r["id"] == rule_id:
            return r
    return None

def get_section_label(rule_id):
    if rule_id <= 5: return "🟦 Основное"
    elif rule_id <= 120: return "🟩 Общее"
    else: return "🟨 Детальное"

def format_rule_message(rule):
    msg = f"<b>{get_section_label(rule['id'])} | Правило #{rule['id']}</b>\n\n"
    msg += f"<b>{rule['title']}</b>\n\n"
    msg += f"<i>{rule['ar']}</i>\n\n"
    msg += f"📋 <b>Кратко:</b>\n{rule['brief']}\n\n"
    if rule.get("proof"):
        msg += f"📖 <b>Довод:</b>\n{rule['proof']}"
    return msg

def build_nav_keyboard(rule_id, section_type):
    keyboard = []
    nav_row = []
    if rule_id > 1:
        nav_row.append(InlineKeyboardButton("◀️ Пред.", callback_data=f"rule_{rule_id - 1}_{section_type}"))
    nav_row.append(InlineKeyboardButton("🏠 Меню", callback_data="main_menu"))
    if rule_id < 220:
        nav_row.append(InlineKeyboardButton("След. ▶️", callback_data=f"rule_{rule_id + 1}_{section_type}"))
    keyboard.append(nav_row)
    return InlineKeyboardMarkup(keyboard)

def build_list_keyboard(rule_ids, section_type, page=0, page_size=10):
    total = len(rule_ids)
    total_pages = (total + page_size - 1) // page_size
    start = page * page_size
    end = min(start + page_size, total)
    keyboard = []
    for i in range(start, end):
        rid = rule_ids[i]
        rule = get_rule_by_id(rid)
        title_short = rule["title"][:40] + ("…" if len(rule["title"]) > 40 else "")
        keyboard.append([InlineKeyboardButton(f"📜 #{rid} {title_short}", callback_data=f"rule_{rid}_{section_type}")])
    nav_row = []
    if page > 0:
        nav_row.append(InlineKeyboardButton("◀️ Назад", callback_data=f"list_{section_type}_{page - 1}"))
    nav_row.append(InlineKeyboardButton("🏠 Меню", callback_data="main_menu"))
    if page < total_pages - 1:
        nav_row.append(InlineKeyboardButton("Далее ▶️", callback_data=f"list_{section_type}_{page + 1}"))
    if nav_row:
        keyboard.append(nav_row)
    return InlineKeyboardMarkup(keyboard), total_pages, page

def get_filtered_rules(section_type):
    if section_type == "main": return [r for r in RULES if r["id"] <= 5]
    elif section_type == "general": return [r for r in RULES if 6 <= r["id"] <= 120]
    elif section_type == "detailed": return [r for r in RULES if r["id"] >= 121]
    elif section_type == "ibadat": return [r for r in RULES if "ibadat" in r["cats"]]
    elif section_type == "muamalat": return [r for r in RULES if "muamalat" in r["cats"]]
    elif section_type == "qada": return [r for r in RULES if "qada" in r["cats"]]
    return RULES

def get_section_name(section_type):
    names = {
        "main": "🟦 Основные правила фикха (1–5)",
        "general": "🟩 Общие большие правила фикха (6–120)",
        "detailed": "🟨 Отраслевые и детальные правила (121–220)",
        "ibadat": "🟦 Ибадат — Поклонение",
        "muamalat": "🟩 Муамалят — Сделки и отношения",
        "qada": "🟥 Каза / Суд — Доказательства",
    }
    return names.get(section_type, "Все правила")

