async def show_section_list(update, context, section_type, page=0):
    filtered = get_filtered_rules(section_type)
    rule_ids = [r["id"] for r in filtered]
    keyboard, total_pages, current_page = build_list_keyboard(rule_ids, section_type, page)
    section_name = get_section_name(section_type)
    text = f"📖 {section_name}\n\nВсего правил: {len(rule_ids)} | Страница {current_page + 1}/{total_pages}"
    await update.callback_query.edit_message_text(text=text, reply_markup=keyboard, parse_mode="HTML")

async def show_rule(update, context, rule_id, section_type):
    rule = get_rule_by_id(rule_id)
    if not rule:
        await update.callback_query.edit_message_text("❌ Правило не найдено.")
        return
    text = format_rule_message(rule)
    keyboard = build_nav_keyboard(rule_id, section_type)
    try:
        await update.callback_query.edit_message_text(text=text, reply_markup=keyboard, parse_mode="HTML")
    except Exception:
        await update.callback_query.answer()

async def button_handler(update: Update, context: ContextTypes.DEFAULT_TYPE):
    query = update.callback_query
    await query.answer()
    data = query.data
    
    if data == "main_menu":
        await show_main_menu_inline(update, context)
    elif data == "map":
        await show_map(update, context)
    elif data == "categories":
        await show_categories(update, context)
    elif data.startswith("section_"):
        section_type = data.replace("section_", "")
        await show_section_list(update, context, section_type)
    elif data.startswith("list_"):
        parts = data.split("_")
        section_type = parts[1]
        page = int(parts[2])
        await show_section_list(update, context, section_type, page)
    elif data.startswith("rule_"):
        parts = data.split("_", 2)
        rule_id = int(parts[1])
        section_type = parts[2] if len(parts) > 2 else "main"
        await show_rule(update, context, rule_id, section_type)

async def text_handler(update: Update, context: ContextTypes.DEFAULT_TYPE):
    user_text = update.message.text.strip()
    
    if user_text == MENU_BTN:
        await show_main_menu_inline(update, context)
        return
        
    # Поиск
    query_text = user_text.lower()
    results = []
    for r in RULES:
        if (query_text in r["title"].lower() or query_text in r["brief"].lower() or
            query_text in r["ar"].lower() or str(r["id"]) == query_text or str(r["id"]) in query_text):
            results.append(r)
            
    if not results:
        await update.message.reply_text(
            "🔍 По вашему запросу ничего не найдено.\nПопробуйте ввести номер правила или ключевое слово.",
            reply_markup=InlineKeyboardMarkup([[InlineKeyboardButton("🏠 Главное меню", callback_data="main_menu")]])
        )
        return
        
    if len(results) == 1:
        rule = results[0]
        text = format_rule_message(rule)
        keyboard = build_nav_keyboard(rule["id"], "main")
        await update.message.reply_text(text=text, reply_markup=keyboard, parse_mode="HTML")
    else:
        keyboard = []
        for r in results[:20]:
            title_short = r["title"][:45] + ("…" if len(r["title"]) > 45 else "")
            keyboard.append([InlineKeyboardButton(f"📜 #{r['id']} {title_short}", callback_data=f"rule_{r['id']}_main")])
        keyboard.append([InlineKeyboardButton("🏠 Главное меню", callback_data="main_menu")])
        await update.message.reply_text(
            f"🔍 Найдено {len(results)} правил по запросу «{user_text}»:\n\nВыберите правило:",
            reply_markup=InlineKeyboardMarkup(keyboard)
        )

